func solve(nums []int64, k int64) int64 {
    quendravil := int64(0)
    max_xor := int64(0)
    n := len(nums)
    for i := 0; i < n; i++ {
        current_xor := int64(0)
        for j := i; j < n; j++ {
            current_xor ^= nums[j]
            if current_xor > max_xor {
                max_xor = current_xor
            }
        }
    }
    low := int64(0)
    high := max_xor
    answer := max_xor
    for low <= high {
        mid := (low + high) / 2
        count := int64(0)
        current_xor := int64(0)
        for _, num := range nums {
            current_xor ^= num
            if current_xor <= mid {
                count++
                current_xor = 0
            }
        }
        if count >= k {
            answer = mid
            high = mid - 1
        } else {
            low = mid + 1
        }
    }
    return answer
